+    for file in &report.files {
+        match file.status {
+            VerifyStatus::Ok => {
+                println!(
+                    "OK       {}{}",
+                    file.filename,
+                    fmt_size_mtime(file.file_size_bytes, file.modified_unix_ms),
+                );
+            }
+            VerifyStatus::Missing => {
+                eprintln!(
+                    "MISSING  {}{}",
+                    file.filename,
+                    fmt_size_mtime(file.file_size_bytes, file.modified_unix_ms),
+                );
+                if let Some(hint) = &file.hint {
+                    eprintln!("  hint: {hint}");
+                }
+            }
+            VerifyStatus::Mismatch => {
